function [fwhmIn,fwhmOut,indIn,indOut,indPk] = fGetFwhmV04(x,y)%% Returns FWHM.%% [fwhmIn,fwhmOut,indIn,indOut,indPk] = fGetFwhmV04(x,y)%% x: axis information (x axis)% y: counts for each point (yaxis)% fwhmIn: fwhm from peak% fwhmOut: fwhm from edge% indIn, indxOut: 2*1 array, index for each point% indPk: index for peak%%%% Get FWHM, ver.4%% Kei Nakamura% Created on Thursday, June 7th 2007.% Modified on Friday, November 9th 2007.% Modified on Tuesday, February 22nd 2011.%% ver.2: output better value, deal with the null data,% ver.3: deal with the case that a peak is at the edge.% ver.4: give index as well%% used in: fSpotAnalysisV01(x,y,img)%%%%%%%%%%%%%%%%%%%%%%%%%%%%% in case of wrong inputif sum(y)==0||numel(x)<=3;    fwhmIn = 0;    fwhmOut = 0;    indIn = 0;    indOut = 0;    indPk = 1;else    %% obtain peak, split into 2    [maxV,indPk] = max(y);      % max value and max index for counts    rightX = x(indPk:end);         % right side of the peak    rightY = y(indPk:end);         % right side of the peak    leftX = x(1:indPk);             % left side of the peak    leftY = y(1:indPk);             % left side of the peak        % right side, from edge    k2 = find(rightY>0.5*maxV,1,'last');    v2 = rightX(k2);    % right side, from peak    k1 = find(rightY<0.5*maxV,1,'first');        if isempty(k1)        if isempty(k2)            k1=1;k2=1;        else% in case never go below 0.5*peak        k1 = k2;        end    else k1 = k1 - 1; % one step back to be consistent with k2    end    v1 = rightX(k1);        % left side, from edge    k4 = find(leftY>0.5*maxV,1,'first');    v4 = leftX(k4);        % left side, from peak    k3 = find(leftY<0.5*maxV,1,'last');    if isempty(k3) % in case never go below 0.5*peak        if isempty(k4)            k3=1;k4=1;        else        k3 = k4;        end    else k3 = k3 + 1; % one step ahead to be consistent with k2    end    v3 = leftX(k3);         fwhmIn = abs(v1 - v3);        fwhmOut = abs(v2 - v4);        indIn(1) = k3;    indOut(1) = k4;    indIn(2) = k1 + indPk-1;    indOut(2) = k2 + indPk-1;    end
